mapper.select:
SELECT la.id, la.phone, la.name, la.identification_number, la.lease_start_date, la.lease_end_date, la.rent, la.deposit, la.status, la.source_type, la.creator_type, la.creator_id, la.application_id, la.auto_generated, la.additional_info, la.create_time, la.update_time, ai.id apartment_id, ai.name apartment_name, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ri.id room_id, ri.room_number, pt.id payment_type_id, pt.name payment_type_name, pt.pay_month_count, lt.id lease_term_id, lt.month_count, lt.unit, DATEDIFF(la.lease_end_date, CURDATE()) as remaining_days FROM lease_agreement la LEFT JOIN apartment_info ai ON la.apartment_id = ai.id AND ai.is_deleted = 0 LEFT JOIN room_info ri ON la.room_id = ri.id AND ri.is_deleted = 0 LEFT JOIN payment_type pt ON la.payment_type_id = pt.id AND pt.is_deleted = 0 LEFT JOIN lease_term lt ON la.lease_term_id = lt.id AND lt.is_deleted = 0
la.is_deleted = 0 AND la.creator_type = 2 AND la.creator_id = #{landlordId}
AND (la.name LIKE CONCAT('%', #{queryVo.keyword}, '%') OR la.phone LIKE CONCAT('%', #{queryVo.keyword}, '%') OR ri.room_number LIKE CONCAT('%', #{queryVo.keyword}, '%'))
AND la.status = #{queryVo.status}
AND la.source_type = #{queryVo.sourceType}
AND la.apartment_id = #{queryVo.apartmentId}
AND la.auto_generated = #{queryVo.autoGenerated}
ORDER BY la.create_time DESC

SELECT COUNT(*)
FROM lease_agreement 
WHERE id = #{leaseId}
  AND creator_type = 2
  AND creator_id = #{landlordId}
  AND is_deleted = 0
